flow-diagram.createChart:
module -> {
	allTypes = $module == null ? list() : $module.get(`tl.model:TLModule#types`);
	classes = $allTypes.filter(t -> $t.instanceOf(`tl.model:TLClass`));
	enums = $allTypes.filter(t -> $t.instanceOf(`tl.model:TLEnumeration`));
	classNameSet = $classes.indexBy(c -> $c.get(`tl.model:TLNamedPart#name`));

	classNodes = $classes.map(c -> {
		props = $c.get(`tl.model:TLStructuredType#localParts`)
			.filter(p -> $p.instanceOf(`tl.model:TLProperty`));
		allGens = $c.get(`tl.model:TLClass#generalizations`);
		externalGens = $allGens
			.filter(g -> $classNameSet[$g.get(`tl.model:TLNamedPart#name`)] == null)
			.map(g -> $g.get(`tl.model:TLType#module`).get(`tl.model:TLNamedPart#name`)
				+ ":" + $g.get(`tl.model:TLNamedPart#name`));

		reactFlowSelection(userObject: $c,
			content: reactFlowBorder(cssClass: "tlSelectionStroke",
				content: reactFlowFill(fill: "white", cssClass: "tlSelectionFill",
					content: reactFlowVertical(gap: 0, contents: [
						reactFlowPadding(all: 6, content: reactFlowAlign(hAlign: "middle",
							content: reactFlowVertical(gap: 2, contents: [
								$c.get(`tl.model:TLClass#abstract`)
									? reactFlowText("\u00ABabstract\u00BB", fontSize: 10, fillStyle: "#888")
									: reactFlowEmpty(),
								reactFlowText($c.get(`tl.model:TLNamedPart#name`), fontWeight: "bold"),
								$externalGens.isEmpty() ? reactFlowEmpty()
									: reactFlowText("extends " + $externalGens.toString(), fontSize: 9, fillStyle: "#888")
							])
						)),
						$props.isEmpty() ? reactFlowEmpty()
							: reactFlowBorder(top: true, left: false, right: false, bottom: false,
								content: reactFlowPadding(all: 6,
									content: reactFlowVertical(gap: 0, contents: $props.map(a ->
										reactFlowSelection(userObject: $a,
											content: reactFlowFill(fill: "transparent", cssClass: "tlSelectionFill",
												content: reactFlowPadding(top: 1, bottom: 1,
													content: reactFlowText(
														$a.get(`tl.model:TLNamedPart#name`)
															+ " : "
															+ $a.get(`tl.model:TLStructuredTypePart#type`).get(`tl.model:TLNamedPart#name`),
														fontSize: 11))))))))
					]))))
	});

	enumNodes = $enums.map(e -> {
		classifiers = $e.get(`tl.model:TLEnumeration#classifiers`);

		reactFlowSelection(userObject: $e,
			content: reactFlowBorder(cssClass: "tlSelectionStroke",
				content: reactFlowFill(fill: "#FFFFF0", cssClass: "tlSelectionFill",
					content: reactFlowVertical(gap: 0, contents: [
						reactFlowPadding(all: 6, content: reactFlowAlign(hAlign: "middle",
							content: reactFlowVertical(gap: 2, contents: [
								reactFlowText("\u00ABenumeration\u00BB", fontSize: 10, fillStyle: "#888"),
								reactFlowText($e.get(`tl.model:TLNamedPart#name`), fontWeight: "bold")
							])
						)),
						$classifiers.isEmpty() ? reactFlowEmpty()
							: reactFlowBorder(top: true, left: false, right: false, bottom: false,
								content: reactFlowPadding(all: 6,
									content: reactFlowVertical(gap: 0, contents: $classifiers.map(cl ->
										reactFlowSelection(userObject: $cl,
											content: reactFlowFill(fill: "transparent", cssClass: "tlSelectionFill",
												content: reactFlowPadding(top: 1, bottom: 1,
													content: reactFlowText($cl.get(`tl.model:TLNamedPart#name`), fontSize: 11))))))))
					]))))
	});

	nodes = list($classNodes, $enumNodes).flatten();
	nodeByName = $nodes.indexBy(n -> $n["userObject"].get(`tl.model:TLNamedPart#name`));

	genEdges = $classes
		.map(c -> $c.get(`tl.model:TLClass#generalizations`)
			.filter(g -> $nodeByName[$g.get(`tl.model:TLNamedPart#name`)] != null)
			.map(g -> reactFlowGraphEdge(
				$nodeByName[$g.get(`tl.model:TLNamedPart#name`)],
				$nodeByName[$c.get(`tl.model:TLNamedPart#name`)],
				priority: 3, sourceSymbol: "CLOSED_ARROW")))
		.flatten();

	refEdges = $classes
		.map(c -> $c.get(`tl.model:TLStructuredType#localParts`)
			.filter(p -> $p.instanceOf(`tl.model:TLReference`))
			.filter(p -> !$p.get(`tl.model:TLReference#backwards`))
			.filter(p -> $nodeByName[$p.get(`tl.model:TLStructuredTypePart#type`).get(`tl.model:TLNamedPart#name`)] != null)
			.map(p -> {
				targetType = $p.get(`tl.model:TLStructuredTypePart#type`);
				refName = $p.get(`tl.model:TLNamedPart#name`);
				mandatory = $p.get(`tl.model:TLStructuredTypePart#mandatory`);
				multiple = $p.get(`tl.model:TLStructuredTypePart#multiple`);
				card = $mandatory ? ($multiple ? "1..*" : "1") : ($multiple ? "*" : "0..1");
				composite = $p.get(`tl.model:TLReference#end`).get(`tl.model:TLAssociationEnd#composite`);

				opposite = $p.get(`tl.model:TLReference#opposite`);
				oppLabel = $opposite != null ? {
					oppName = $opposite.get(`tl.model:TLNamedPart#name`);
					oppMandatory = $opposite.get(`tl.model:TLStructuredTypePart#mandatory`);
					oppMultiple = $opposite.get(`tl.model:TLStructuredTypePart#multiple`);
					oppCard = $oppMandatory ? ($oppMultiple ? "1..*" : "1") : ($oppMultiple ? "*" : "0..1");
					reactFlowDecoration(
						reactFlowPadding(reactFlowText($oppName + "\n" + $oppCard, fontSize: 10), all: 4),
						linePosition: 0.0)
				} : null;

				$composite
					? reactFlowGraphEdge(
						$nodeByName[$c.get(`tl.model:TLNamedPart#name`)],
						$nodeByName[$targetType.get(`tl.model:TLNamedPart#name`)],
						priority: 2,
						sourceSymbol: "FILLED_DIAMOND",
						decorations: $oppLabel != null
							? list($oppLabel,
								reactFlowDecoration(
									reactFlowPadding(reactFlowText($refName + "\n" + $card, fontSize: 10), all: 4),
									linePosition: 1.0))
							: list(
								reactFlowDecoration(
									reactFlowPadding(reactFlowText($refName + "\n" + $card, fontSize: 10), all: 4),
									linePosition: 1.0)),
						userObject: $p)
					: reactFlowGraphEdge(
						$nodeByName[$c.get(`tl.model:TLNamedPart#name`)],
						$nodeByName[$targetType.get(`tl.model:TLNamedPart#name`)],
						priority: 1,
						targetSymbol: "ARROW",
						decorations: $oppLabel != null
							? list($oppLabel,
								reactFlowDecoration(
									reactFlowPadding(reactFlowText($refName + "\n" + $card, fontSize: 10), all: 4),
									linePosition: 1.0))
							: list(
								reactFlowDecoration(
									reactFlowPadding(reactFlowText($refName + "\n" + $card, fontSize: 10), all: 4),
									linePosition: 1.0)),
						userObject: $p)
			}))
		.flatten();

	$nodes.isEmpty()
		? reactFlowChart()
		: reactFlowChart(
			root: reactFlowPadding(all: 20,
				content: reactFlowGraphLayout($nodes,
					list($genEdges, $refEdges).flatten())))
}
